mapper.sql:
ot.level = 'PLATFORM' AND ot.company_id = #{platformCompanyId}
AND UPPER(ot.status) = UPPER(#{status})
AND ( LOWER(ot.name) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(COALESCE(ot.description, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(COALESCE(ot.department_type_code, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%') )

mapper.select:
SELECT
trd.task_template_id,
trd.document_id
FROM task_template_required_documents trd
INNER JOIN task_templates tt
ON tt.task_template_id = trd.task_template_id
INNER JOIN checklist_templates ct
ON ct.checklist_template_id = tt.checklist_template_id
WHERE trd.company_id = #{platformCompanyId}
AND tt.company_id = #{platformCompanyId}
AND ct.company_id = #{platformCompanyId}
AND ct.onboarding_template_id = #{templateId}

SELECT COUNT(1)
FROM onboarding_instances
WHERE onboarding_template_id = #{templateId}

mapper.delete:
DELETE FROM task_template_required_documents trd
USING task_templates tt, checklist_templates ct
WHERE trd.task_template_id = tt.task_template_id
AND tt.checklist_template_id = ct.checklist_template_id
AND trd.company_id = #{platformCompanyId}
AND tt.company_id = #{platformCompanyId}
AND ct.company_id = #{platformCompanyId}
AND ct.onboarding_template_id = #{templateId}

DELETE FROM task_templates tt
USING checklist_templates ct
WHERE tt.checklist_template_id = ct.checklist_template_id
AND tt.company_id = #{platformCompanyId}
AND ct.company_id = #{platformCompanyId}
AND ct.onboarding_template_id = #{templateId}

DELETE FROM checklist_templates
WHERE company_id = #{platformCompanyId}
AND onboarding_template_id = #{templateId}

DELETE FROM onboarding_templates
WHERE company_id = #{platformCompanyId}
AND level = 'PLATFORM'
AND onboarding_template_id = #{templateId}
